            $createQuery = str_replace("\r\n", $crlf, $createQuery);
        } elseif (mb_strpos($createQuery, "(\n ")) {
            $createQuery = str_replace("\n", $crlf, $createQuery);
        } elseif (mb_strpos($createQuery, "(\r ")) {
            $createQuery = str_replace("\r", $crlf, $createQuery);
